INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('2e36cd23-68ec-4303-a32d-ff666a850490', '8561733b-e658-40d9-aaaf-c0faf7827e13', 'Speedy Soft 30', 'speedy-soft-30', 'This Speedy Soft 30 highlights the House’s reimagining of the iconic Monogram in an updated Monogram Emblème signature, which is artfully crafted from jacquard canvas to create an embroidery-inspired finish. Blending excellence and innovation, this edition is offered in a Peuplier colorway and is trimmed with a contrasting leather strap and braided handles, plus an exclusive LV address tag. It is sized to fit essential items, including a tablet.', 69000000.00, NULL, true, false, '[]', 4, '2026-06-24 14:43:54.630021+07', '2026-06-24 14:44:22.687689+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('c2029b6e-cce7-40e1-a0f7-a7f13ff7899b', '323c213b-e16e-486a-aa2c-c95ab4f28b2b', 'My Monogram Fame Rectangle Sunglasses', 'my-monogram-fame-rectangle-sunglasses', 'Louis Vuitton’s bestselling My Monogram signature gets an on-trend update with the My Monogram Fame Rectangle sunglasses. The House’s iconic flowers and initials are incorporated into a cool, sleek design with lenses covering the front of the frames. Light and comfortable, they go perfectly with any outfit, bringing a contemporary twist to a classic look.', 9450000.00, NULL, true, false, '[]', 1, '2026-06-24 15:15:02.327708+07', '2026-06-24 15:15:02.327708+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('5ee8ba8d-bda7-46c1-81d7-08131115e53d', '332a8332-3913-4399-b2de-f167e2f5db74', 'Monogram Accent Pleat Dress', 'monogram-accent-pleat-dress', 'This elegant dress is crafted from fluid silk crepe de chine in a mid-length silhouette with a clean neckline and romantic bishop sleeves. Crisp pleats add structure to the front and back, while the chest and tone-on-tone belt are trimmed with metallic Monogram accents for a sophisticated signature finish.', 77500000.00, NULL, true, false, '[]', 10, '2026-06-24 15:21:11.724572+07', '2026-06-24 15:21:58.67697+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('f1a72e8d-5edd-4fc4-abf8-2a42e62a9ed1', '24f1e4a3-be88-47ac-9ae6-020a46d10e33', 'Buckle Up Handkerchief', 'buckle-up-handkerchief', 'This skirt is bold and breezy in fluid silk twill cut with a graphic handkerchief hemline with gathering around the waist emphasizing the airy volume. It is printed all over with this season’s Buckle Up motif, which playfully pays homage to functional details from the House’s iconic Leather Goods collection.', 61000000.00, NULL, true, false, '[]', 1, '2026-06-24 15:26:36.197844+07', '2026-06-24 15:26:51.6536+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('b20d1b54-2083-4452-9336-6d3661511354', '323c213b-e16e-486a-aa2c-c95ab4f28b2b', 'LV Super Vision Light Pilot Sunglasse', 'lv-super-vision-light-pilot-sunglasse', 'The LV Super Vision Light pilot sunglasses are a self-assured pair with bold detailing. A silver-toned metal silhouette features blue lenses with complementary temple tips, creating a versatile and easygoing palette. Inscriptions around the lenses nodding to the Louis Vuitton history are inspired by cameras, and the nose pads add extra comfort to the lightweight construction.', 10400000.00, NULL, true, false, '[]', 2, '2026-06-24 15:33:37.346631+07', '2026-06-24 15:33:37.346631+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('ed443a90-be17-4599-94d6-1a02d2892751', '80bb16d6-d80c-4997-85bf-ca21063232fc', 'LV Tilted Sneaker', 'lv-tilted-sneaker', 'This eye-catching iteration of the LV Tilted sneaker comes in embroidered, distressed canvas with an asymmetrical pattern. Both the upper and the thick rubber outsole appear to have been splashed with paint, creating an artistic, hand-crafted look. The upper features trim in emblematic natural leather, while the outsole bears a tilted LV Initials signature.', 26100000.00, NULL, true, false, '[]', 2, '2026-06-24 15:35:23.738627+07', '2026-06-24 15:35:23.738627+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('e55ea9cd-ab2c-4fb4-8cf0-9fae913c5d7b', '686bf01c-0ca1-40ac-9d5c-0e95e20abcc0', 'LV Iconic Earrings', 'lv-iconic-earrings', '', 8300000.00, NULL, true, false, '[]', 1, '2026-06-24 15:40:45.094799+07', '2026-06-24 15:40:45.094799+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('9418c1ca-0de8-49f5-921d-7bbfe648d0d1', '686bf01c-0ca1-40ac-9d5c-0e95e20abcc0', 'LV Iconic Bracelet', 'lv-iconic-bracelet', 'Incorporating the House''s distinguished symbols into casual looks is effortless with the LV Iconic bracelet. This dainty piece is adorned with LV Initials encrusted with shimmery crystals, a tiny Monogram Flower and a finely engraved plaque. The adjuster chain at the back ends with a dangling LV Circle charm for an additional signature flourish.', 8950000.00, NULL, true, false, '[]', 2, '2026-06-24 15:42:23.547142+07', '2026-06-24 15:42:23.547142+07');
INSERT INTO public.products (id, category_id, name, slug, description, price, compare_at_price, is_available, is_featured, tags, display_order, created_at, updated_at) VALUES ('1bba9ec7-5d4c-40f5-b0a3-fcfd06b158ac', '686bf01c-0ca1-40ac-9d5c-0e95e20abcc0', 'LV Pearly Confetti Necklace', 'lv-pearly-confetti-necklace', '', 13800000.00, NULL, true, false, '[]', 3, '2026-06-24 15:44:11.455156+07', '2026-06-24 15:44:11.455156+07');
